import app.k9mail.core.android.common.contact.ContactRepository
import app.k9mail.core.android.testing.RobolectricTest
import assertk.assertThat
import assertk.assertions.isEqualTo
import com.fsck.k9.CoreResourceProvider
import com.fsck.k9.TestCoreResourceProvider
import com.fsck.k9.mail.Address
import org.junit.Test
import org.mockito.kotlin.mock

class MessageHelperRecipientDisplayNamesTest : RobolectricTest() {

    private val contactRepository: ContactRepository = mock()

    @Test
    fun getRecipientDisplayNames_addsSpaceBetweenPrefixAndRecipients() {
        val messageHelper = MessageHelper(
            resourceProvider = TestCoreResourceProvider(),
            contactRepository = contactRepository,
        )

        val recipients = messageHelper.getRecipientDisplayNames(arrayOf(Address("alice@example.com")))

        assertThat(recipients.toString()).isEqualTo("To: alice@example.com")
    }

    @Test
    fun getRecipientDisplayNames_doesNotAddExtraSpaceWhenPrefixAlreadyEndsWithWhitespace() {
        val base = TestCoreResourceProvider()
        val resourceProvider = object : CoreResourceProvider by base {
            override fun contactDisplayNamePrefix(): String = "To: "
        }

        val messageHelper = MessageHelper(
            resourceProvider = resourceProvider,
            contactRepository = contactRepository,
        )

        val recipients = messageHelper.getRecipientDisplayNames(arrayOf(Address("alice@example.com")))

        assertThat(recipients.toString()).isEqualTo("To: alice@example.com")
    }
}
"}

